  AND COLUMN_NAME IN ('UpdateDate','LastUpdateDate','ModificationDate','ReportDateID','DateID','EOD_Date','EODDate','SnapshotDate','LoadDate','InsertDate','CreateDate','Date')
ORDER BY TABLE_NAME, COLUMN_NAME
